/**
 * pi-speak — Voice readback extension for Pi
 *
 * When the agent finishes a turn, this extension:
 *   1. Speaks a short voice ping: what was done + which tmux session
 *   2. Registers alt+r (or configured shortcut) to replay / stop the last response
 *   3. Shows a status widget below the editor
 *
 * Settings: see ~/.config/pi-speak/config.json
 * API key: set UNREAL_SPEECH_API_KEY in your environment (source ~/.env in your shell)
 * Optional: OPENROUTER_API_KEY for smarter voice ping summaries
 */

import { execSync } from "node:child_process";
import type { ExtensionAPI } from "@mariozechner/pi-coding-agent";
import { getValidationErrors, initConfig, loadConfig } from "./config/index";
import { configureDebug, debug, debugError, setDebugEnabled } from "./debug";
import { stripMarkdown } from "./helpers";
import { createPlatform, isMacMuted, isPlatformSupported } from "./platform";
import { summarizeForPing } from "./summarizer";
import { TTSPlayer } from "./tts";

export interface UI {
  setWidget(key: string, content: string[] | undefined): void;
  notify(msg: string, type: "info" | "warning" | "error"): void;
}

export default function (pi: ExtensionAPI) {
  const config = loadConfig();
  setDebugEnabled(config.debug.enabled);
  configureDebug(config.debug);

  // Warn if platform is not supported (defer until session_start to have access to ctx.ui)
  const platformNotSupported = !isPlatformSupported();

  const platform = createPlatform();
  const player = new TTSPlayer(platform, config);

  // ── State ──────────────────────────────────────────────────────────────────

  let lastResponseText = "";
  let disabled = false;
  let sessionName = "";
  let wasMutedOnLastResponse = false;

  // ── Extract assistant text ────────────────────────────────────────────────

  function extractAssistantText(
    messages: Array<{ role?: string; content?: string | Array<{ type: string; text?: string }> }>
  ): string {
    for (let i = messages.length - 1; i >= 0; i--) {
      const msg = messages[i];
      if (msg?.role !== "assistant") continue;

      const textParts: string[] = [];
      const content = msg.content;

      if (typeof content === "string") {
        textParts.push(content);
      } else if (Array.isArray(content)) {
        for (const block of content) {
          if (block.type === "text" && typeof block.text === "string") {
            textParts.push(block.text);
          }
        }
      }

      if (textParts.length > 0) {
        return stripMarkdown(textParts.join("\n"));
      }
    }
    return "";
  }

  /** Build widget content: validation errors first, then normal status */
  function buildWidgetContent(normalLine: string): string[] {
    const validationErrors = getValidationErrors();
    if (validationErrors.length === 0) return [normalLine];
    const errorLines = validationErrors.map(
      err =>
        `⚠️ ${err.path}: ${err.message}` +
        (err.value !== undefined && typeof err.value !== "object" ? ` (got ${JSON.stringify(err.value)})` : "")
    );
    return [...errorLines, normalLine];
  }

  // ── Session start ─────────────────────────────────────────────────────────

  pi.on("session_start", async (_event, ctx) => {
    debug("=== session_start ===");

    // Warn if platform is not supported
    if (platformNotSupported) {
      debug(`platform "${process.platform}" is not supported — audio playback disabled`);
      ctx.ui.notify(
        `speak: platform "${process.platform}" is not supported. Only macOS is supported for audio playback.`,
        "warning"
      );
      ctx.ui.setWidget("speak", ["🔊 Platform not supported"]);
    }

    // Check if system is muted
    if (isMacMuted()) {
      debug("session_start: system is muted — voice readback will be skipped");
      ctx.ui.notify("speak: system is muted — voice readback disabled. Unmute to enable.", "warning");
    }

    // Capture session name for voice ping
    if (process.env.TMUX_PANE) {
      try {
        sessionName = execSync(`tmux display-message -p -t '${process.env.TMUX_PANE}' '#{session_name}'`, {
          encoding: "utf-8",
          stdio: ["pipe", "pipe", "pipe"]
        }).trim();
      } catch {
        sessionName = "";
      }
    }

    // Create default config file if missing
    initConfig();

    // Check for required API key (should be set in user's environment)
    // Check env var first, then fall back to config file
    const apiKey = process.env.UNREAL_SPEECH_API_KEY ?? config.api.unrealSpeechKey;
    if (!apiKey) {
      disabled = true;
      debug("session_start: NO API KEY — extension disabled");
      ctx.ui.notify(
        "speak: UNREAL_SPEECH_API_KEY not set — voice readback disabled. Set it in your environment (e.g., source ~/.env)",
        "warning"
      );
      ctx.ui.setWidget("speak", undefined);
      return;
    }

    // Clear stale audio cache from previous sessions
    player.clearCache();

    debug("session_start: API key loaded, extension enabled");
    ctx.ui.setWidget("speak", buildWidgetContent("🔊 " + config.behavior.shortcut + " read aloud"));
  });

  // ── Agent end ─────────────────────────────────────────────────────────────

  pi.on("agent_end", async (event, ctx) => {
    debug("=== agent_end ===");
    if (disabled) {
      debug("agent_end: SKIPPED (disabled)");
      return;
    }

    // Check mute status dynamically to save API costs
    const muted = isMacMuted();
    wasMutedOnLastResponse = muted;

    if (muted) {
      debug("agent_end: SKIPPED (system is muted)");
      ctx.ui.setWidget("speak", buildWidgetContent("🔇 Muted  " + config.behavior.shortcut + " replay"));
      return;
    }

    const text = extractAssistantText(event.messages);
    debug(`agent_end: extracted text length=${text.length} preview="${text.slice(0, 80)}"`);
    if (!text) {
      debug("agent_end: no assistant text — skipping");
      return;
    }

    // Clear cached audio from previous response (conversation moved on)
    if (text !== lastResponseText) {
      debug(`agent_end: new response (${text.length} chars), clearing old cache`);
      player.clearCache();
    }
    lastResponseText = text;
    ctx.ui.setWidget("speak", buildWidgetContent("🔊 Ready  " + config.behavior.shortcut + " replay"));

    // Skip ping if disabled
    if (!config.behavior.pingEnabled) {
      debug("agent_end: ping disabled — skipping");
      return;
    }

    // Generate short voice ping summary (LLM if OpenRouter key, else fallback)
    const ping = await summarizeForPing({
      responseText: text,
      sessionName: sessionName || undefined,
      config: config.summarizer,
      apiKey: config.api.openRouterKey ?? undefined,
      fallbackPingText: config.behavior.fallbackPingText
    });
    debug(`agent_end: voice ping = "${ping}"`);

    // Speak the ping (short, not cached — alt+r replays the full response)
    player.ping(ping);
  });

  // ── Shortcut: alt+r — replay / stop ───────────────────────────────────────

  // eslint-disable-next-line @typescript-eslint/no-explicit-any
  pi.registerShortcut(config.behavior.shortcut as any, {
    description: "Replay last response aloud / stop current playback",
    handler: ctx => {
      debug(`=== shortcut: ${config.behavior.shortcut} pressed ===`);
      if (disabled) {
        debug(`shortcut: SKIPPED (disabled)`);
        return;
      }

      if (isMacMuted()) {
        debug(`shortcut: SKIPPED (system is muted)`);
        ctx.ui.notify("speak: system is muted — unmute to hear responses", "info");
        return;
      }

      if (player.playing) {
        debug(`shortcut: STOP (was playing)`);
        player.stop();
        ctx.ui.setWidget("speak", buildWidgetContent("🔊 Ready  " + config.behavior.shortcut + " replay"));
        return;
      }

      if (!lastResponseText) {
        debug(`shortcut: no response to replay`);
        ctx.ui.notify("speak: no response to replay yet", "info");
        return;
      }

      // Check if we need to regenerate (was muted when response came)
      if (wasMutedOnLastResponse || player.cachedFiles.length === 0) {
        debug(`shortcut: regenerating audio (was muted or no cache)`);
        ctx.ui.setWidget("speak", buildWidgetContent("🔊 Generating...  " + config.behavior.shortcut + " stop"));
        player.speak(lastResponseText, ctx.ui);
        return;
      }

      debug(`shortcut: REPLAY (text length=${lastResponseText.length})`);
      try {
        player.speak(lastResponseText, ctx.ui);
      } catch (err) {
        debugError("shortcut: speak() threw", err);
        ctx.ui.notify(`speak: replay error — ${err instanceof Error ? err.message : String(err)}`, "error");
      }
    }
  });
}

